pub fn value_eq(&self, other: &Header) -> bool {
    match *self {
        Header::Field { ref value, .. } => {
            let a = value;
            match *other {
                Header::Field { ref value, .. } => a == value,
                _ => false,
            }
        }
        Header::Authority(ref a) => match *other {
            Header::Authority(ref b) => a == b,
            _ => false,
        },
        Header::Method(ref a) => match *other {
            Header::Method(ref b) => a == b,
            _ => false,
        },
        Header::Scheme(ref a) => match *other {
            Header::Scheme(ref b) => a == b,
            _ => false,
        },
        Header::Path(ref a) => match *other {
            Header::Path(ref b) => a == b,
            _ => false,
        },
        Header::Protocol(ref a) => match *other {
            Header::Protocol(ref b) => a == b,
            _ => false,
        },
        Header::Status(ref a) => match *other {
            Header::Status(ref b) => a == b,
            _ => false,
        },
    }
}

pub(crate) fn send_pending_ping<T, B>(
    &mut self,
    cx: &mut Context,
    dst: &mut Codec<T, B>,
) -> Poll<io::Result<()>>
where
    T: AsyncWrite + Unpin,
    B: Buf,
{
    if let Some(ref mut ping) = self.pending_ping {
        if !ping.sent {
            if !dst.poll_ready(cx)?.is_ready() {
                return Poll::Pending;
            }

            dst.buffer(Ping::new(ping.payload).into())
                .expect("invalid ping frame");
            ping.sent = true;
        }
    } else if let Some(ref users) = self.user_pings {
        if users.0.state.load(Ordering::Acquire) == USER_STATE_PENDING_PING {
            if !dst.poll_ready(cx)?.is_ready() {
                return Poll::Pending;
            }

            dst.buffer(Ping::new(Ping::USER).into())
                .expect("invalid ping frame");
            users
                .0
                .state
                .store(USER_STATE_PENDING_PONG, Ordering::Release);
        } else {
            users.0.ping_task.register(cx.waker());
        }
    }

    Poll::Ready(Ok(()))
}

fn decode<'i, I: Iterator<Item = &'i HeaderValue>>(values: &mut I) -> Result<Self, Error> {
    values
        .next()
        .and_then(|v| v.to_str().ok())
        .and_then(|s| split_in_two(s, ' '))
        .and_then(|(unit, spec)| {
            if unit != "bytes" {
                // For now, this only supports bytes-content-range. nani?
                return None;
            }

            let (range, complete_length) = split_in_two(spec, '/')?;

            let complete_length = if complete_length == "*" {
                None
            } else {
                Some(complete_length.parse().ok()?)
            };

            let range = if range == "*" {
                None
            } else {
                let (first_byte, last_byte) = split_in_two(range, '-')?;
                let first_byte = first_byte.parse().ok()?;
                let last_byte = last_byte.parse().ok()?;
                if last_byte < first_byte {
                    return None;
                }
                Some((first_byte, last_byte))
            };

            Some(ContentRange {
                range,
                complete_length,
            })
        })
        .ok_or_else(Error::invalid)
}

fn expand_derive_has_sql_type_struct(
    input: &DeriveInput,
    fields: &Punctuated<Field, Comma>,
) -> syn::Result<TokenStream> {
    let attributes = check_struct_attributes(input, fields)?;

    let ident = &input.ident;
    let mut tts = TokenStream::new();

    if cfg!(feature = "postgres") {
        let ty_name = type_name(ident, attributes.type_name.as_ref());

        tts.extend(quote!(
            #[automatically_derived]
            impl ::sqlx::Type<::sqlx::Postgres> for #ident {
                fn type_info() -> ::sqlx::postgres::PgTypeInfo {
                    ::sqlx::postgres::PgTypeInfo::with_name(#ty_name)
                }
            }
        ));

        if !attributes.no_pg_array {
            tts.extend(quote!(
                #[automatically_derived]
                impl ::sqlx::postgres::PgHasArrayType for #ident  {
                    fn array_type_info() -> ::sqlx::postgres::PgTypeInfo {
                        ::sqlx::postgres::PgTypeInfo::array_of(#ty_name)
                    }
                }
            ));
        }
    }

    Ok(tts)
}

fn expand_derive_has_sql_type_weak_enum(
    input: &DeriveInput,
    variants: &Punctuated<Variant, Comma>,
) -> syn::Result<TokenStream> {
    let attrs = check_weak_enum_attributes(input, variants)?;
    let repr = attrs.repr.unwrap();
    let ident = &input.ident;
    let mut ts = quote!(
        #[automatically_derived]
        impl<DB: ::sqlx::Database> ::sqlx::Type<DB> for #ident
        where
            #repr: ::sqlx::Type<DB>,
        {
            fn type_info() -> DB::TypeInfo {
                <#repr as ::sqlx::Type<DB>>::type_info()
            }

            fn compatible(ty: &DB::TypeInfo) -> bool {
                <#repr as ::sqlx::Type<DB>>::compatible(ty)
            }
        }
    );

    if cfg!(feature = "postgres") && !attrs.no_pg_array {
        ts.extend(quote!(
            #[automatically_derived]
            impl ::sqlx::postgres::PgHasArrayType for #ident  {
                fn array_type_info() -> ::sqlx::postgres::PgTypeInfo {
                    <#repr as ::sqlx::postgres::PgHasArrayType>::array_type_info()
                }
            }
        ));
    }

    Ok(ts)
}

fn removes_child() {
    let a = LNode::Element {
        name: "div".into(),
        attrs: vec![],
        children: vec![
            LNode::Element {
                name: "button".into(),
                attrs: vec![],
                children: vec![LNode::Text("foo".into())],
            },
            LNode::Element {
                name: "button".into(),
                attrs: vec![],
                children: vec![LNode::Text("bar".into())],
            },
        ],
    };
    let b = LNode::Element {
        name: "div".into(),
        attrs: vec![],
        children: vec![LNode::Element {
            name: "button".into(),
            attrs: vec![],
            children: vec![LNode::Text("foo".into())],
