    assert_eq!(
        delta,
        vec![Patch {
            path: vec![],
            action: PatchAction::RemoveChild { at: 1 }
        },]
    );
}

fn parse(input: syn::parse::ParseStream) -> syn::Result<Self> {
    let mut item = ItemStruct::parse(input)?;

    let docs = Docs::new(&item.attrs);

    let props = item
        .fields
        .clone()
        .into_iter()
        .map(Prop::new)
        .collect::<Vec<_>>();

    // We need to remove the `#[doc = ""]` and `#[builder(_)]`
    // attrs from the function signature
    drain_filter(&mut item.attrs, |attr| match &attr.meta {
        Meta::NameValue(attr) => attr.path == parse_quote!(doc),
        Meta::List(attr) => attr.path == parse_quote!(prop),
        _ => false,
    });
    item.fields.iter_mut().for_each(|arg| {
        drain_filter(&mut arg.attrs, |attr| match &attr.meta {
            Meta::NameValue(attr) => attr.path == parse_quote!(doc),
            Meta::List(attr) => attr.path == parse_quote!(prop),
            _ => false,
        });
    });

    Ok(Self {
        docs,
        vis: item.vis.clone(),
        name: convert_from_snake_case(&item.ident),
        props,
        body: item,
    })
}

pub fn Header<G: Html>(cx: Scope) -> View<G> {
    let app_state = use_context::<AppState>(cx);
    let value = create_signal(cx, String::new());
    let input_ref = create_node_ref(cx);

    let handle_submit = |event: Event| {
        let event: KeyboardEvent = event.unchecked_into();

        if event.key() == "Enter" {
            let mut task = value.get().as_ref().clone();
            task = task.trim().to_string();

            if !task.is_empty() {
                app_state.add_todo(task, 0);
                value.set("".to_string());
                input_ref
                    .get::<DomNode>()
                    .unchecked_into::<HtmlInputElement>()
                    .set_value("");
            }
        }
    };

    view! { cx,
        header(class="header") {
            h1 { "todos" }
            input(ref=input_ref,
                class="new-todo",
                placeholder="What needs to be done?",
                bind:value=value,
                on:keyup=handle_submit,
            )
        }
    }
}

fn try_new_req_multipart(
    path: &str,
    accepts: &str,
    body: Self::FormData,
    method: Method,
) -> Result<Self, E> {
    let (abort_ctrl, abort_signal) = abort_signal();
    let server_url = get_server_url();
    let mut url = String::with_capacity(server_url.len() + path.len());
    url.push_str(server_url);
    url.push_str(path);
    Ok(Self(SendWrapper::new(RequestInner {
        request: match method {
            Method::POST => Request::post(&url),
            Method::PATCH => Request::patch(&url),
            Method::PUT => Request::put(&url),
            m => {
                return Err(E::from_server_fn_error(
                    ServerFnErrorErr::UnsupportedRequestMethod(
                        m.to_string(),
                    ),
                ))
            }
        }
        .header("Accept", accepts)
        .abort_signal(abort_signal.as_ref())
        .body(body.0.take())
        .map_err(|e| {
            E::from_server_fn_error(ServerFnErrorErr::Request(
                e.to_string(),
            ))
        })?,
        abort_ctrl,
    })))
}

fn rebuild(self, state: &mut Self::State) {
    // set or update A -- `None` just means "no change"
    match (self.a, &mut state.a) {
        (Some(new), Some(old)) => new.rebuild(old),
        (Some(new), None) => state.a = Some(new.build()),
        _ => {}
    }

    // set or update B
    match (self.b, &mut state.b) {
        (Some(new), Some(old)) => new.rebuild(old),
        (Some(new), None) => state.b = Some(new.build()),
        _ => {}
    }

    match (self.show_b, state.showing_b) {
        // transition from A to B
        (true, false) => match (&mut state.a, &mut state.b) {
            (Some(a), Some(b)) => {
                a.insert_before_this(b);
                a.unmount();
            }
            _ => unreachable!(),
        },
        // transition from B to A
        (false, true) => match (&mut state.a, &mut state.b) {
            (Some(a), Some(b)) => {
                b.insert_before_this(a);
                b.unmount();
            }
            _ => unreachable!(),
        },
        _ => {}
    }
    state.showing_b = self.show_b;
}

