fn exec_insert_with_returning<A, C>(
    primary_key: Option<ValueTuple>,
    mut insert_statement: InsertStatement,
    db: &C,
) -> Result<<A::Entity as EntityTrait>::Model, DbErr>
where
    <A::Entity as EntityTrait>::Model: IntoActiveModel<A>,
    C: ConnectionTrait,
    A: ActiveModelTrait,
{
    let db_backend = db.get_database_backend();
    let found = match db.support_returning() {
        true => {
            let returning = Query::returning().exprs(
                <A::Entity as EntityTrait>::Column::iter()
                    .map(|c| c.select_as(c.into_returning_expr(db_backend))),
            );
            insert_statement.returning(returning);
            ReturningSelector::<SelectModel<<A::Entity as EntityTrait>::Model>, _>::from_query(
                insert_statement,
            )
            .one(db)?
        }
        false => {
            let insert_res = exec_insert::<A, _>(primary_key, insert_statement, db)?;
            <A::Entity as EntityTrait>::find_by_id(insert_res.last_insert_id).one(db)?
        }
    };
    match found {
        Some(model) => Ok(model),
        None => Err(DbErr::RecordNotFound(
            "Failed to find inserted item".to_owned(),
        )),
    }
}

fn new(input: syn::DeriveInput) -> Result<Self, syn::Error> {
    let sea_attr = derive_attr::SeaOrm::try_from_attributes(&input.attrs)?.unwrap_or_default();

    let ident = input.ident;
    let column_ident = sea_attr.column.unwrap_or_else(|| format_ident!("Column"));
    let model_ident = sea_attr.model.unwrap_or_else(|| format_ident!("Model"));
    let model_ex_ident = sea_attr.model_ex.unwrap_or_else(|| format_ident!("Model"));
    let active_model_ident = sea_attr
        .active_model
        .unwrap_or_else(|| format_ident!("ActiveModel"));
    let active_model_ex_ident = sea_attr
        .active_model_ex
        .unwrap_or_else(|| format_ident!("ActiveModel"));
    let primary_key_ident = sea_attr
        .primary_key
        .unwrap_or_else(|| format_ident!("PrimaryKey"));
    let relation_ident = sea_attr
        .relation
        .unwrap_or_else(|| format_ident!("Relation"));

    let table_name = sea_attr.table_name;
    let schema_name = sea_attr.schema_name;

    Ok(DeriveEntity {
        column_ident,
        ident,
        model_ident,
        model_ex_ident,
        active_model_ident,
        active_model_ex_ident,
        primary_key_ident,
        relation_ident,
        schema_name,
        table_name,
    })
}

fn test_from_column_def() {
    let column: Column = ColumnDef::new(Alias::new("id")).string().to_owned().into();
    assert_eq!(
        column.get_def().to_string(),
        quote! {
            ColumnType::String(StringLen::None).def().null()
        }
        .to_string()
    );

    let column: Column = ColumnDef::new(Alias::new("id"))
        .string()
        .not_null()
        .to_owned()
        .into();
    assert!(column.not_null);

    let column: Column = ColumnDef::new(Alias::new("id"))
        .string()
        .unique_key()
        .not_null()
        .to_owned()
        .into();
    assert!(column.unique);
    assert!(column.not_null);

    let column: Column = ColumnDef::new(Alias::new("id"))
        .string()
        .auto_increment()
        .unique_key()
        .not_null()
        .to_owned()
        .into();
    assert!(column.auto_increment);
    assert!(column.unique);
    assert!(column.not_null);
}

fn test_nested_transaction_1() {
    let db = MockDatabase::new(DbBackend::Postgres).into_connection();

    db.transaction::<_, (), DbErr>(|txn| {
        let _ = cake::Entity::find().one(txn);

        txn.transaction::<_, (), DbErr>(|txn| {
            let _ = fruit::Entity::find().all(txn);

            Ok(())
        })
        .unwrap();

        Ok(())
    })
    .unwrap();

    assert_eq!(
        db.into_transaction_log(),
        [Transaction::many([
            Statement::from_string(DbBackend::Postgres, "BEGIN"),
            Statement::from_sql_and_values(
                DbBackend::Postgres,
                r#"SELECT "cake"."id", "cake"."name" FROM "cake" LIMIT $1"#,
                [1u64.into()]
            ),
            Statement::from_string(DbBackend::Postgres, "SAVEPOINT savepoint_1"),
            Statement::from_sql_and_values(
                DbBackend::Postgres,
                r#"SELECT "fruit"."id", "fruit"."name", "fruit"."cake_id" FROM "fruit""#,
                []
            ),
            Statement::from_string(DbBackend::Postgres, "RELEASE SAVEPOINT savepoint_1"),
            Statement::from_string(DbBackend::Postgres, "COMMIT"),
        ]),]
    );
}

pub(crate) fn find_linked_recursive<E>(
    mut initial_query: Select<E>,
    mut link: Vec<LinkDef>,
) -> Select<E>
where
    E: EntityTrait,
{
    let cte_name = Alias::new("cte");

    let Some(first) = link.first_mut() else {
        return initial_query;
    };
    first.from_tbl = cte_name.clone().into_table_ref();
    let mut recursive_query: Select<E> =
        find_linked(link.into_iter().rev(), JoinType::InnerJoin).select_only();
    initial_query.query.exprs_mut_for_each(|expr| {
        recursive_query.query.expr(expr.clone());
    });

    let mut cte_query = initial_query.query.clone();
    cte_query.union(UnionType::All, recursive_query.query);

    let cte = CommonTableExpression::new()
        .table_name(cte_name.clone())
        .query(cte_query)
        .to_owned();

    let mut select = E::find().select_only();
    initial_query.query.exprs_mut_for_each(|expr| {
        select.query.expr(expr.clone());
    });
    select
        .query
        .from_clear()
        .from_as(cte_name, E::default())
        .with_cte(cte);
    select
}

